25	  async function loadSettings() {
26	    const response = await fetch("/api/settings/tibero");
27	    const payload = (await response.json()) as { success: boolean; data?: GlobalSettings | null };
28	
29	    if (payload.success && payload.data?.tiberoConfig) {
