61	      setSettingsMessage(error instanceof Error ? error.message : "설정 저장에 실패했습니다.");
62	    } finally {
63	      setSettingsLoading(false);
64	    }
65	  }
66	
67	  useEffect(() => {
68	    void loadScenarios();
69	    void loadSettings();
70	  }, []);
71	
72	  return (
73	    <main className="px-4 py-8">
74	      <div className="mb-6 flex items-center justify-between gap-4">
