79	          </p>
80	        </div>
81	        <Link href="/scenarios/new">
82	          <Button>+ 새 시나리오</Button>
83	        </Link>
84	      </div>
85	
86	      <section className="mb-8 rounded-xl border bg-card p-5">
87	        <div className="mb-4 flex items-center justify-between gap-4">
88	          <div>
89	            <h2 className="text-lg font-semibold">전역 Tibero 설정</h2>
90	            <p className="text-sm text-muted-foreground">
91	              여기서 저장한 값은 새 시나리오 작성 시 기본값으로 사용됩니다.
92	            </p>
93	          </div>
94	          <Button disabled={settingsLoading} onClick={handleSaveSettings}>
95	            {settingsLoading ? "저장 중..." : "설정 저장"}
96	          </Button>
97	        </div>
98	
99	        <div className="grid gap-2 md:grid-cols-2">
100	          <input
101	            className="rounded border px-2 py-1 text-sm"
102	            placeholder="Host"
103	            value={settings.host}
104	            onChange={(event) => setSettings({ ...settings, host: event.target.value })}
105	          />
106	          <input
107	            className="rounded border px-2 py-1 text-sm"
108	            placeholder="Port"
109	            type="number"
110	            value={settings.port}
111	            onChange={(event) =>
112	              setSettings({ ...settings, port: Number(event.target.value || "0") })
113	            }
114	          />
115	          <input
116	            className="rounded border px-2 py-1 text-sm"
117	            placeholder="Username"
118	            value={settings.username}
119	            onChange={(event) => setSettings({ ...settings, username: event.target.value })}
120	          />
121	          <input
122	            className="rounded border px-2 py-1 text-sm"
123	            placeholder="Password"
124	            type="password"
125	            value={settings.password}
126	            onChange={(event) => setSettings({ ...settings, password: event.target.value })}
127	          />
128	          <input
129	            className="rounded border px-2 py-1 text-sm md:col-span-2"
130	            placeholder="Service Name"
131	            value={settings.serviceName}
132	            onChange={(event) => setSettings({ ...settings, serviceName: event.target.value })}
133	          />
134	        </div>
135	
136	        {settingsMessage && <p className="mt-3 text-sm text-blue-700">{settingsMessage}</p>}
137	      </section>
138	
139	      {scenarios.length === 0 ? (
140	        <div className="rounded-xl border border-dashed p-12 text-center text-muted-foreground">
141	          저장된 시나리오가 없습니다.
142	        </div>
143	      ) : (
144	        <div className="grid gap-4 md:grid-cols-2 xl:grid-cols-3">
145	          {scenarios.map((scenario) => (
146	            <ScenarioCard key={scenario.id} scenario={scenario} onDelete={handleDelete} />
147	          ))}
148	        </div>
149	      )}
150	    </main>
151	  );
152	}
