1	import fs from "node:fs";
2	import path from "node:path";
3	import type { RunHistory } from "./types.js";
4	
5	const RUNS_DIR = path.join(process.cwd(), "data", "runs");
6	
7	function ensureDir() {
8	  if (!fs.existsSync(RUNS_DIR)) {
9	    fs.mkdirSync(RUNS_DIR, { recursive: true });
10	  }
11	}
12	
13	function assertSafeId(id: string): void {
14	  if (!/^[\w-]+$/.test(id)) {
15	    throw new Error(`Invalid run id: ${id}`);
16	  }
17	}
18	
19	function filePath(id: string): string {
20	  assertSafeId(id);
21	  ensureDir();
22	
23	  for (const entry of fs.readdirSync(RUNS_DIR)) {
24	    if (!entry.endsWith(".json")) {
25	      continue;
26	    }
27	
28	    const candidatePath = path.join(RUNS_DIR, entry);
29	
30	    try {
31	      const run = JSON.parse(fs.readFileSync(candidatePath, "utf-8")) as RunHistory;
32	      if (run.id === id) {
33	        return candidatePath;
34	      }
35	    } catch {
36	      continue;
37	    }
38	  }
39	
40	  return path.join(RUNS_DIR, `${Date.now()}-${id}.json`);
41	}
42	
43	export function listRunHistories(scenarioId?: string): RunHistory[] {
44	  ensureDir();
45	
46	  const runs = fs
47	    .readdirSync(RUNS_DIR)
48	    .filter((entry) => entry.endsWith(".json"))
49	    .map((entry) => {
50	      try {
51	        return JSON.parse(
52	          fs.readFileSync(path.join(RUNS_DIR, entry), "utf-8")
53	        ) as RunHistory;
54	      } catch {
55	        return null;
56	      }
57	    })
58	    .filter((run): run is RunHistory => run !== null);
59	
60	  if (scenarioId !== undefined) {
61	    return runs.filter((run) => run.scenarioId === scenarioId);
62	  }
63	
64	  return runs;
65	}
66	
67	export function getRunHistory(id: string): RunHistory | null {
68	  assertSafeId(id);
69	  ensureDir();
70	
71	  for (const entry of fs.readdirSync(RUNS_DIR)) {
72	    if (!entry.endsWith(".json")) {
73	      continue;
74	    }
75	
76	    const candidatePath = path.join(RUNS_DIR, entry);
77	
78	    try {
79	      const run = JSON.parse(fs.readFileSync(candidatePath, "utf-8")) as RunHistory;
80	      if (run.id === id) {
81	        return run;
82	      }
83	    } catch {
84	      continue;
85	    }
86	  }
87	
88	  return null;
89	}
90	
91	export function saveRunHistory(run: RunHistory): void {
92	  assertSafeId(run.id);
93	  ensureDir();
94	
95	  const existing = getRunHistory(run.id);
96	  let targetPath: string;
97	
98	  if (existing !== null) {
99	    targetPath = filePath(run.id);
100	  } else {
101	    targetPath = path.join(RUNS_DIR, `${Date.now()}-${run.id}.json`);
102	  }
103	
104	  fs.writeFileSync(targetPath, JSON.stringify(run, null, 2), "utf-8");
105	}
106	
107	export function deleteRunHistory(id: string): boolean {
108	  assertSafeId(id);
109	  ensureDir();
110	
111	  for (const entry of fs.readdirSync(RUNS_DIR)) {
112	    if (!entry.endsWith(".json")) {
113	      continue;
114	    }
115	
116	    const candidatePath = path.join(RUNS_DIR, entry);
117	
118	    try {
119	      const run = JSON.parse(fs.readFileSync(candidatePath, "utf-8")) as RunHistory;
120	      if (run.id === id) {
121	        fs.unlinkSync(candidatePath);
122	        return true;
123	      }
124	    } catch {
125	      continue;
126	    }
127	  }
128	
129	  return false;
130	}
131	
132	export function setGolden(id: string, isGolden: boolean): boolean {
133	  assertSafeId(id);
134	  ensureDir();
135	
136	  const target = getRunHistory(id);
137	  if (target === null) {
138	    return false;
139	  }
140	
141	  if (isGolden) {
142	    // 같은 scenarioId의 기존 골든 셋 해제
143	    for (const entry of fs.readdirSync(RUNS_DIR)) {
144	      if (!entry.endsWith(".json")) {
145	        continue;
146	      }
147	
148	      const candidatePath = path.join(RUNS_DIR, entry);
149	
150	      try {
151	        const run = JSON.parse(fs.readFileSync(candidatePath, "utf-8")) as RunHistory;
152	        if (run.scenarioId === target.scenarioId && run.isGolden && run.id !== id) {
153	          run.isGolden = false;
154	          fs.writeFileSync(candidatePath, JSON.stringify(run, null, 2), "utf-8");
155	        }
156	      } catch {
157	        continue;
158	      }
159	    }
160	  }
161	
162	  // 대상 run의 isGolden 갱신
163	  target.isGolden = isGolden;
164	  fs.writeFileSync(filePath(id), JSON.stringify(target, null, 2), "utf-8");
165	
166	  return true;
167	}
