import { NextResponse } from "next/server";
import type { NextRequest } from "next/server";
import { listRunHistories } from "@/lib/run-history-manager";

export async function GET(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url);
    const scenarioId = searchParams.get("scenarioId") ?? undefined;
    const runs = listRunHistories(scenarioId).sort(
      (a, b) => new Date(b.executedAt).getTime() - new Date(a.executedAt).getTime()
    );
    return NextResponse.json({ success: true, data: runs });
  } catch (error) {
    return NextResponse.json({ success: false, error: String(error) }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import type { NextRequest } from "next/server";
import { deleteRunHistory } from "@/lib/run-history-manager";

export async function DELETE(
  _request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id } = await params;
    const deleted = deleteRunHistory(id);
    if (!deleted) {
      return NextResponse.json({ success: false, error: "Run not found" }, { status: 404 });
    }
    return NextResponse.json({ success: true });
  } catch (error) {
    return NextResponse.json({ success: false, error: String(error) }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import type { NextRequest } from "next/server";
import { setGolden } from "@/lib/run-history-manager";

export async function PUT(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const { id } = await params;
    const body = (await request.json()) as { isGolden: boolean };
    const updated = setGolden(id, body.isGolden);
    if (!updated) {
      return NextResponse.json({ success: false, error: "Run not found" }, { status: 404 });
    }
    return NextResponse.json({ success: true });
  } catch (error) {
    return NextResponse.json({ success: false, error: String(error) }, { status: 500 });
  }
}

