"use client";

import Link from "next/link";
import { useEffect, useState } from "react";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import type { RunHistory, Scenario } from "@/lib/types";

function statusVariant(status: RunHistory["status"]) {
  if (status === "passed") return "success";
  if (status === "failed") return "destructive";
  return "warning";
}

function statusLabel(status: RunHistory["status"]) {
  if (status === "passed") return "통과";
  if (status === "failed") return "실패";
  return "오류";
}

export default function RunsPage() {
  const [scenarios, setScenarios] = useState<Scenario[]>([]);
  const [selectedId, setSelectedId] = useState<string>("");
  const [runs, setRuns] = useState<RunHistory[]>([]);
  const [loading, setLoading] = useState(false);

  async function loadScenarios() {
    const res = await fetch("/api/scenarios");
    const payload = (await res.json()) as { success: boolean; data?: Scenario[] };
    if (payload.success && payload.data) {
      setScenarios(payload.data);
    }
  }

  async function loadRuns(scenarioId: string) {
    if (!scenarioId) {
      setRuns([]);
      return;
    }
    setLoading(true);
    try {
      const res = await fetch(`/api/runs?scenarioId=${scenarioId}`);
      const payload = (await res.json()) as { success: boolean; data?: RunHistory[] };
      if (payload.success && payload.data) {
        setRuns(payload.data);
      }
    } finally {
      setLoading(false);
    }
  }

  async function handleSetGolden(id: string) {
    await fetch(`/api/runs/${id}/golden`, {
      method: "PUT",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ isGolden: true }),
    });
    await loadRuns(selectedId);
  }

  async function handleDelete(id: string) {
    if (!window.confirm("이 실행 이력을 삭제하시겠습니까?")) return;
    await fetch(`/api/runs/${id}`, { method: "DELETE" });
    await loadRuns(selectedId);
  }

  useEffect(() => {
    void loadScenarios();
  }, []);

  useEffect(() => {
    void loadRuns(selectedId);
  }, [selectedId]);

  return (
    <main className="px-4 py-8">
      <div className="mb-6 flex items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold">실행 이력</h1>
          <p className="text-sm text-muted-foreground">시나리오별 테스트 실행 이력을 조회합니다.</p>
        </div>
        {selectedId && (
          <Link href={`/runs/${selectedId}`}>
            <Button variant="outline">대시보드 보기</Button>
          </Link>
        )}
      </div>

      <div className="mb-6">
        <select
          className="rounded border px-3 py-2 text-sm"
          value={selectedId}
          onChange={(e) => setSelectedId(e.target.value)}
        >
          <option value="">시나리오를 선택하세요</option>
          {scenarios.map((s) => (
            <option key={s.id} value={s.id}>
              {s.name}
            </option>
          ))}
        </select>
      </div>

      {loading && <p className="text-sm text-muted-foreground">불러오는 중...</p>}

      {!loading && selectedId && runs.length === 0 && (
        <div className="rounded-xl border border-dashed p-12 text-center text-muted-foreground">
          실행 이력이 없습니다.
        </div>
      )}

      {!loading && runs.length > 0 && (
        <div className="overflow-x-auto rounded-xl border">
          <table className="w-full text-sm">
            <thead className="bg-muted/50">
              <tr>
                <th className="px-4 py-3 text-left font-semibold">실행 일시</th>
                <th className="px-4 py-3 text-left font-semibold">상태</th>
                <th className="px-4 py-3 text-left font-semibold">골든 셋</th>
                <th className="px-4 py-3 text-right font-semibold">작업</th>
              </tr>
            </thead>
            <tbody className="divide-y">
              {runs.map((run) => (
                <tr key={run.id} className="hover:bg-muted/30">
                  <td className="px-4 py-3 font-mono text-xs">
                    {new Date(run.executedAt).toLocaleString("ko-KR")}
                  </td>
                  <td className="px-4 py-3">
                    <Badge variant={statusVariant(run.status)}>{statusLabel(run.status)}</Badge>
                  </td>
                  <td className="px-4 py-3">
                    {run.isGolden ? (
                      <Badge variant="info">골든 셋</Badge>
                    ) : (
                      <span className="text-muted-foreground">-</span>
                    )}
                  </td>
                  <td className="px-4 py-3">
                    <div className="flex justify-end gap-2">
                      {!run.isGolden && (
                        <Button
                          size="sm"
                          variant="outline"
                          onClick={() => handleSetGolden(run.id)}
                        >
                          골든 지정
                        </Button>
                      )}
                      <Button
                        size="sm"
                        variant="destructive"
                        onClick={() => handleDelete(run.id)}
                      >
                        삭제
                      </Button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </main>
  );
}
'@

