"use client";

import { useEffect, useState } from "react";
import { Badge } from "@/components/ui/badge";
import type { RunHistory, StepResult } from "@/lib/types";

function cellClass(status: StepResult["status"]) {
  if (status === "passed") return "bg-green-100";
  return "bg-red-100";
}

export default function RunDashboardPage({
  params,
}: {
  params: Promise<{ scenarioId: string }>;
}) {
  const [scenarioId, setScenarioId] = useState<string>("");
  const [runs, setRuns] = useState<RunHistory[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    params.then((p) => {
      setScenarioId(p.scenarioId);
    }).catch(() => undefined);
  }, [params]);

  useEffect(() => {
    if (!scenarioId) return;
    setLoading(true);
    fetch(`/api/runs?scenarioId=${scenarioId}`)
      .then((res) => res.json() as Promise<{ success: boolean; data?: RunHistory[] }>)
      .then((payload) => {
        if (payload.success && payload.data) {
          // 최신 순 정렬 후 최대 10개
          const sorted = [...payload.data].sort(
            (a, b) => new Date(b.executedAt).getTime() - new Date(a.executedAt).getTime()
          );
          setRuns(sorted.slice(0, 10));
        }
      })
      .catch(() => undefined)
      .finally(() => setLoading(false));
  }, [scenarioId]);

  if (loading) {
    return (
      <main className="px-4 py-8">
        <p className="text-sm text-muted-foreground">불러오는 중...</p>
      </main>
    );
  }

  if (runs.length === 0) {
    return (
      <main className="px-4 py-8">
        <p className="text-sm text-muted-foreground">실행 이력이 없습니다.</p>
      </main>
    );
  }

  // 히트맵용 데이터 구조 구성
  // 행: testCaseName + stepIndex (dbQuery 포함 전체 스텝)
  // 열: 실행 회차 (최신 순)
  const firstRun = runs[0];
  type RowKey = { testCaseName: string; stepIndex: number; stepDesc: string };
  const rowKeys: RowKey[] = [];

  for (const tc of firstRun.testCaseResults) {
    tc.stepResults.forEach((sr, si) => {
      rowKeys.push({
        testCaseName: tc.testCaseName,
        stepIndex: si,
        stepDesc: sr.step.description ?? sr.step.type,
      });
    });
  }

  // 골든 실행 찾기
  const goldenRun = runs.find((r) => r.isGolden) ?? null;

  // DB diff용: dbQuery 스텝만
  type DbRow = { testCaseName: string; stepIndex: number; queryId: string };
  const dbRows: DbRow[] = [];
  for (const tc of firstRun.testCaseResults) {
    tc.stepResults.forEach((sr, si) => {
      if (sr.step.type === "dbQuery") {
        dbRows.push({
          testCaseName: tc.testCaseName,
          stepIndex: si,
          queryId: (sr.step as { queryId: string }).queryId,
        });
      }
    });
  }

  function getStepResult(run: RunHistory, testCaseName: string, stepIndex: number): StepResult | null {
    const tc = run.testCaseResults.find((t) => t.testCaseName === testCaseName);
    if (!tc) return null;
    return tc.stepResults[stepIndex] ?? null;
  }

  return (
    <main className="px-4 py-8 space-y-10">
      <div>
        <h1 className="text-2xl font-bold mb-1">실행 대시보드</h1>
        <p className="text-sm text-muted-foreground">최근 {runs.length}회 실행 결과를 히트맵으로 확인합니다.</p>
      </div>

      {/* 히트맵 */}
      <section>
        <h2 className="text-lg font-semibold mb-3">테스트케이스 히트맵</h2>
        <div className="overflow-x-auto rounded-xl border">
          <table className="text-xs border-collapse">
            <thead>
              <tr>
                <th className="border px-3 py-2 bg-muted/50 text-left whitespace-nowrap">
                  테스트케이스 / 스텝
                </th>
                {runs.map((run) => (
                  <th
                    key={run.id}
                    className="border px-2 py-2 bg-muted/50 text-center whitespace-nowrap font-normal"
                  >
                    {run.isGolden && <span className="mr-0.5">⭐</span>}
                    {new Date(run.executedAt).toLocaleDateString("ko-KR", {
                      month: "2-digit",
                      day: "2-digit",
                      hour: "2-digit",
                      minute: "2-digit",
                    })}
                  </th>
                ))}
              </tr>
            </thead>
            <tbody>
              {rowKeys.map((row, ri) => (
                <tr key={ri}>
                  <td className="border px-3 py-1.5 whitespace-nowrap bg-muted/20">
                    <span className="font-medium">{row.testCaseName}</span>
                    <span className="ml-1 text-muted-foreground">#{row.stepIndex + 1} {row.stepDesc}</span>
                  </td>
                  {runs.map((run) => {
                    const sr = getStepResult(run, row.testCaseName, row.stepIndex);
                    return (
                      <td
                        key={run.id}
                        className={`border px-2 py-1.5 text-center ${sr ? cellClass(sr.status) : "bg-gray-50"}`}
                        title={sr?.status ?? "데이터 없음"}
                      >
                        {sr ? (sr.status === "passed" ? "✓" : "✗") : "-"}
                      </td>
                    );
                  })}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </section>

      {/* DB diff */}
      <section>
        <h2 className="text-lg font-semibold mb-3">DB Query 결과 비교</h2>
        {goldenRun === null ? (
          <div className="rounded-xl border border-dashed p-8 text-center text-muted-foreground">
            골든 셋을 먼저 지정하세요. 실행 이력 목록에서 골든 지정 버튼을 사용하세요.
          </div>
        ) : dbRows.length === 0 ? (
          <div className="rounded-xl border border-dashed p-8 text-center text-muted-foreground">
            dbQuery 스텝이 없습니다.
          </div>
        ) : (
          <div className="space-y-4">
            {dbRows.map((row, ri) => {
              const goldenSr = getStepResult(goldenRun, row.testCaseName, row.stepIndex);
              const latestRun = runs.find((r) => !r.isGolden) ?? runs[0];
              const latestSr = getStepResult(latestRun, row.testCaseName, row.stepIndex);

              const goldenOut = JSON.stringify(goldenSr?.output ?? null, null, 2);
              const latestOut = JSON.stringify(latestSr?.output ?? null, null, 2);
              const isDifferent = goldenOut !== latestOut;

              return (
                <div
                  key={ri}
                  className={`rounded-xl border-2 p-4 ${isDifferent ? "border-red-400" : "border-green-400"}`}
                >
                  <div className="mb-2 flex items-center gap-2">
                    <Badge variant={isDifferent ? "destructive" : "success"}>
                      {isDifferent ? "다름" : "동일"}
                    </Badge>
                    <span className="text-sm font-medium">
                      {row.testCaseName} — 스텝 #{row.stepIndex + 1} ({row.queryId})
                    </span>
                  </div>
                  <div className="grid grid-cols-2 gap-3">
                    <div>
                      <p className="mb-1 text-xs font-semibold text-muted-foreground">
                        골든 셋 ({new Date(goldenRun.executedAt).toLocaleDateString("ko-KR")})
                      </p>
                      <pre className="max-h-48 overflow-auto rounded border bg-muted/30 p-2 text-xs">
                        {goldenOut}
                      </pre>
                    </div>
                    <div>
                      <p className="mb-1 text-xs font-semibold text-muted-foreground">
                        최신 실행 ({new Date(latestRun.executedAt).toLocaleDateString("ko-KR")})
                      </p>
                      <pre className="max-h-48 overflow-auto rounded border bg-muted/30 p-2 text-xs">
                        {latestOut}
                      </pre>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </section>
    </main>
  );
}
'@

